class Solution(object):
    def maxScore(self, n, k, stayScore, travelScore):
        # dp[city] = max points after completing day i ending at city
        INF = float('-inf')
        dp = [0] * n  # Can start at any city

        for day in range(k):
            new_dp = [INF] * n
            for dest in range(n):
                # Stay at dest
                new_dp[dest] = max(new_dp[dest], dp[dest] + stayScore[day][dest])
                # Travel from any other city
                for src in range(n):
                    if src != dest:
                        new_dp[dest] = max(new_dp[dest],
                                          dp[src] + travelScore[src][dest])
            dp = new_dp

        return max(dp)
